import { TestingModule } from '@nestjs/testing';
import { DataSource, Repository } from 'typeorm';
import { createIntegrationTestModule, cleanDatabase } from './setup';
import { Payment } from '../../src/entities/payment.entity';
import { buildPayment } from '../factories/payment.factory';
import { Refund } from '../../src/entities/refund.entity';
import { buildRefund } from '../factories/refund.factory';

describe('Payment Relationships', () => {
  let module: TestingModule;
  let dataSource: DataSource;
  let repository: Repository<Payment>;

  beforeAll(async () => {
    module = await createIntegrationTestModule();
    dataSource = module.get(DataSource);
    repository = dataSource.getRepository(Payment);
  });

  afterEach(async () => {
    await cleanDatabase(dataSource);
  });

  afterAll(async () => {
    await module.close();
  });

  describe('has_many refunds', () => {
    it('loads children via relation', async () => {
      const parentData = buildPayment();
      const parent = await repository.save(repository.create(parentData));

      const childRepo = dataSource.getRepository(Refund);
      const childData = buildRefund({ paymentId: parent.id });
      await childRepo.save(childRepo.create(childData));

      const loaded = await repository.findOne({
        where: { id: parent.id } as Record<string, unknown>,
        relations: ['refunds'],
      });
      expect(loaded).not.toBeNull();
      expect(loaded!.refunds).toBeDefined();
      expect(loaded!.refunds.length).toBeGreaterThanOrEqual(1);
    });
  });
});
